dashboard.definition:
{
    "title": "Agentic Usage · Overview",
    "description": "",
    "inputs": {
        "input_time": {
            "options": {
                "defaultValue": "-7d@h,now",
                "token": "tr"
            },
            "title": "Time Range",
            "type": "input.timerange"
        },
        "input_user": {
            "dataSources": {
                "primary": "ds_userlist"
            },
            "options": {
                "defaultValue": "All",
                "items": [
                    {
                        "label": "All Users",
                        "value": "All"
                    }
                ],
                "token": "selected_user"
            },
            "title": "User",
            "type": "input.dropdown"
        },
        "input_service": {
            "options": {
                "defaultValue": "All",
                "items": [
                    {
                        "label": "All Harnesses",
                        "value": "All"
                    },
                    {
                        "label": "Claude Code",
                        "value": "claude-code"
                    },
                    {
                        "label": "Claude Desktop",
                        "value": "claude-code-desktop"
                    },
                    {
                        "label": "Cowork",
                        "value": "cowork"
                    },
                    {
                        "label": "Gemini CLI",
                        "value": "gemini-cli"
                    },
                    {
                        "label": "Codex",
                        "value": "codex"
                    }
                ],
                "token": "selected_service"
            },
            "title": "Harness",
            "type": "input.dropdown"
        },
        "input_theme": {
            "options": {
                "defaultValue": "#0a0c10",
                "items": [
                    {
                        "label": "Dark",
                        "value": "#0a0c10"
                    },
                    {
                        "label": "Light",
                        "value": "#f4f6f8"
                    }
                ],
                "token": "theme"
            },
            "title": "Theme",
            "type": "input.dropdown"
        }
    },
    "defaults": {
        "dataSources": {}
    },
    "visualizations": {
        "viz_users": {
            "type": "agentic_usage.cu_kpi",
            "options": {
                "agentic_usage.cu_kpi.theme": "$theme$",
                "agentic_usage.cu_kpi.label": "DISTINCT USERS",
                "agentic_usage.cu_kpi.valueField": "value",
                "agentic_usage.cu_kpi.hero": "false",
                "agentic_usage.cu_kpi.accentColor": "#f2643d"
            },
            "dataSources": {
                "primary": "ds_users"
            }
        },
        "viz_tokens": {
            "type": "agentic_usage.cu_kpi",
            "options": {
                "agentic_usage.cu_kpi.theme": "$theme$",
                "agentic_usage.cu_kpi.label": "TOTAL TOKENS",
                "agentic_usage.cu_kpi.valueField": "value",
                "agentic_usage.cu_kpi.hero": "true",
                "agentic_usage.cu_kpi.accentColor": "#28b6a4"
            },
            "dataSources": {
                "primary": "ds_tokens"
            }
        },
        "viz_cost": {
            "type": "agentic_usage.cu_kpi",
            "options": {
                "agentic_usage.cu_kpi.theme": "$theme$",
                "agentic_usage.cu_kpi.label": "EST. COST · CLAUDE ONLY",
                "agentic_usage.cu_kpi.valueField": "value",
                "agentic_usage.cu_kpi.hero": "false",
                "agentic_usage.cu_kpi.accentColor": "#f2643d"
            },
            "dataSources": {
                "primary": "ds_cost"
            }
        },
        "viz_loc": {
            "type": "agentic_usage.cu_kpi",
            "options": {
                "agentic_usage.cu_kpi.theme": "$theme$",
                "agentic_usage.cu_kpi.label": "NET LINES OF CODE",
                "agentic_usage.cu_kpi.valueField": "value",
                "agentic_usage.cu_kpi.unit": "K",
                "agentic_usage.cu_kpi.hero": "false",
                "agentic_usage.cu_kpi.accentColor": "#e6b24a"
            },
            "dataSources": {
                "primary": "ds_loc"
            }
        },
        "viz_cache": {
            "type": "agentic_usage.cu_kpi",
            "options": {
                "agentic_usage.cu_kpi.theme": "$theme$",
                "agentic_usage.cu_kpi.label": "CACHE HIT RATIO",
                "agentic_usage.cu_kpi.valueField": "value",
                "agentic_usage.cu_kpi.unit": "%",
                "agentic_usage.cu_kpi.hero": "false",
                "agentic_usage.cu_kpi.accentColor": "#52b487"
            },
            "dataSources": {
                "primary": "ds_cache"
            }
        },
        "viz_leaderboard": {
            "type": "agentic_usage.cu_leaderboard",
            "options": {
                "agentic_usage.cu_leaderboard.theme": "$theme$",
                "agentic_usage.cu_leaderboard.title": "Team Leaderboard",
                "agentic_usage.cu_leaderboard.metricField": "Tokens (M)",
                "agentic_usage.cu_leaderboard.metricColLabel": "Tokens (M)",
                "agentic_usage.cu_leaderboard.metricLabel": "tokens",
                "agentic_usage.cu_leaderboard.metricUnit": "M",
                "agentic_usage.cu_leaderboard.nameField": "User",
                "agentic_usage.cu_leaderboard.serviceField": "Service",
                "agentic_usage.cu_leaderboard.costField": "Cost ($)",
                "agentic_usage.cu_leaderboard.cacheField": "Cache %"
            },
            "dataSources": {
                "primary": "ds_leaderboard"
            }
        },
        "viz_area": {
            "type": "agentic_usage.cu_area",
            "options": {
                "agentic_usage.cu_area.theme": "$theme$",
                "agentic_usage.cu_area.title": "Token Usage by Hour",
                "agentic_usage.cu_area.valueDivisor": "1000000",
                "agentic_usage.cu_area.valueUnit": "M",
                "agentic_usage.cu_area.readField": "cache_read",
                "agentic_usage.cu_area.createField": "cache_creation",
                "agentic_usage.cu_area.readLabel": "cache_read",
                "agentic_usage.cu_area.createLabel": "cache_creation"
            },
            "dataSources": {
                "primary": "ds_timeline"
            }
        },
        "viz_ratelimit": {
            "type": "agentic_usage.cu_stat",
            "options": {
                "agentic_usage.cu_stat.theme": "$theme$",
                "agentic_usage.cu_stat.label": "Rate-limit · 429s",
                "agentic_usage.cu_stat.bigField": "value",
                "agentic_usage.cu_stat.accentColor": "#f2643d",
                "agentic_usage.cu_stat.kv1Label": "peak hour",
                "agentic_usage.cu_stat.kv1Field": "peak_hour",
                "agentic_usage.cu_stat.kv2Label": "worst user",
                "agentic_usage.cu_stat.kv2Field": "worst_user",
                "agentic_usage.cu_stat.footnoteField": "foot"
            },
            "dataSources": {
                "primary": "ds_ratelimit"
            }
        },
        "viz_adoption": {
            "type": "agentic_usage.cu_stat",
            "options": {
                "agentic_usage.cu_stat.theme": "$theme$",
                "agentic_usage.cu_stat.label": "Team adoption",
                "agentic_usage.cu_stat.bigField": "value",
                "agentic_usage.cu_stat.suffix": "active devs",
                "agentic_usage.cu_stat.accentColor": "#ffffff",
                "agentic_usage.cu_stat.barField": "pct",
                "agentic_usage.cu_stat.barColor": "#28b6a4",
                "agentic_usage.cu_stat.footnoteField": "foot"
            },
            "dataSources": {
                "primary": "ds_adoption"
            }
        },
        "viz_models": {
            "type": "agentic_usage.cu_donut",
            "options": {
                "agentic_usage.cu_donut.theme": "$theme$",
                "agentic_usage.cu_donut.title": "AI Models Used",
                "agentic_usage.cu_donut.sublabel": "token share",
                "agentic_usage.cu_donut.labelField": "model",
                "agentic_usage.cu_donut.valueField": "value",
                "agentic_usage.cu_donut.valueDivisor": "1000000000",
                "agentic_usage.cu_donut.valueUnit": "B"
            },
            "dataSources": {
                "primary": "ds_models"
            }
        },
        "viz_heatmap": {
            "type": "agentic_usage.cu_heatmap",
            "options": {
                "agentic_usage.cu_heatmap.theme": "$theme$",
                "agentic_usage.cu_heatmap.title": "Activity Heatmap",
                "agentic_usage.cu_heatmap.subtitle": "tokens by date & hour",
                "agentic_usage.cu_heatmap.dayField": "d",
                "agentic_usage.cu_heatmap.hourField": "h",
                "agentic_usage.cu_heatmap.valueField": "v",
                "agentic_usage.cu_heatmap.valueDivisor": "1000000",
                "agentic_usage.cu_heatmap.valueUnit": "M"
            },
            "dataSources": {
                "primary": "ds_heatmap"
            }
        },
        "viz_banner": {
            "type": "agentic_usage.cu_checklist",
            "options": {
                "agentic_usage.cu_checklist.theme": "$theme$",
                "agentic_usage.cu_checklist.displayMode": "banner",
                "agentic_usage.cu_checklist.linkView": "agentic_health",
                "agentic_usage.cu_checklist.linkLabel": "Open Data Health →"
            },
            "dataSources": {
                "primary": "ds_banner"
            }
        },
        "viz_drift": {
            "type": "agentic_usage.cu_stat",
            "options": {
                "agentic_usage.cu_stat.theme": "$theme$",
                "agentic_usage.cu_stat.label": "Contract drift",
                "agentic_usage.cu_stat.bigField": "value",
                "agentic_usage.cu_stat.accentColor": "#f2643d",
                "agentic_usage.cu_stat.kv1Label": "no-relationship pts",
                "agentic_usage.cu_stat.kv1Field": "norel",
                "agentic_usage.cu_stat.kv2Label": "tokenless api_req",
                "agentic_usage.cu_stat.kv2Field": "tokenless",
                "agentic_usage.cu_stat.footnoteField": "foot"
            },
            "dataSources": {
                "primary": "ds_drift"
            }
        },
        "viz_harness": {
            "type": "agentic_usage.cu_donut",
            "options": {
                "agentic_usage.cu_donut.theme": "$theme$",
                "agentic_usage.cu_donut.title": "Harness Mix",
                "agentic_usage.cu_donut.sublabel": "token share",
                "agentic_usage.cu_donut.labelField": "harness",
                "agentic_usage.cu_donut.valueField": "value",
                "agentic_usage.cu_donut.valueDivisor": "1000000000",
                "agentic_usage.cu_donut.valueUnit": "B"
            },
            "dataSources": {
                "primary": "ds_harness"
            }
        }
    },
    "dataSources": {
        "ds_userlist": {
            "type": "ds.search",
            "options": {
                "query": "| mstats fillnull_value=\"__missing__\" count(_value) AS points WHERE `agentic_metrics` metric_name=\"agentic.token.usage\" BY \"user.email\" \"user.id\" \"service.name\" \"agentic.token.relationship\" \"agentic.harness.name\" | eval identity=case('user.email'!=\"__missing__\",'user.email','user.id'!=\"__missing__\",'user.id',true(),null()) | eval svc0='service.name', hn0='agentic.harness.name' | eval hkey=`harness_key(svc0,hn0)` | where 'agentic.token.relationship' IN (\"total\",\"exclusive\") | where \"$selected_service$\"==\"All\" OR hkey==\"$selected_service$\" | where isnotnull(identity) | stats count BY identity | eval value=identity, label=identity | sort label | fields label value",
                "queryParameters": {
                    "earliest": "$tr.earliest$",
                    "latest": "$tr.latest$"
                }
            }
        },
        "ds_users": {
            "type": "ds.search",
            "options": {
                "refresh": "60s",
                "refreshType": "delay",
                "query": "| mstats fillnull_value=\"__missing__\" count(_value) AS points WHERE `agentic_metrics` metric_name=\"agentic.token.usage\" BY \"user.email\" \"user.id\" \"service.name\" \"agentic.token.relationship\" \"agentic.harness.name\" | eval identity=case('user.email'!=\"__missing__\",'user.email','user.id'!=\"__missing__\",'user.id',true(),null()) | eval svc0='service.name', hn0='agentic.harness.name' | eval hkey=`harness_key(svc0,hn0)` | where 'agentic.token.relationship' IN (\"total\",\"exclusive\") | where \"$selected_user$\"==\"All\" OR identity==\"$selected_user$\" | where \"$selected_service$\"==\"All\" OR hkey==\"$selected_service$\" | stats dc(identity) AS value | where value>0 | appendpipe [| stats count | where count=0 | eval _status=\"Configure local/macros.conf to point at your telemetry indexes\", value=0]",
                "queryParameters": {
                    "earliest": "$tr.earliest$",
                    "latest": "$tr.latest$"
                }
            }
        },
        "ds_tokens": {
            "type": "ds.search",
            "options": {
                "refresh": "60s",
                "refreshType": "delay",
                "query": "| mstats fillnull_value=\"__missing__\" sum(_value) AS total WHERE `agentic_metrics` metric_name=\"agentic.token.usage\" BY \"user.email\" \"user.id\" \"service.name\" \"agentic.token.relationship\" \"agentic.harness.name\" | eval identity=case('user.email'!=\"__missing__\",'user.email','user.id'!=\"__missing__\",'user.id',true(),null()) | eval svc0='service.name', hn0='agentic.harness.name' | eval hkey=`harness_key(svc0,hn0)` | where 'agentic.token.relationship' IN (\"total\",\"exclusive\") | where \"$selected_user$\"==\"All\" OR identity==\"$selected_user$\" | where \"$selected_service$\"==\"All\" OR hkey==\"$selected_service$\" | stats sum(total) AS total | where isnotnull(total) | eval value=case(total>=1000000000, round(total/1000000000,1).\"B\", total>=1000000, round(total/1000000,1).\"M\", total>=1000, round(total/1000,1).\"K\", 1=1, tostring(total)) | fields value | appendpipe [| stats count | where count=0 | eval _status=\"Awaiting data\", value=\"0\"]",
                "queryParameters": {
                    "earliest": "$tr.earliest$",
                    "latest": "$tr.latest$"
                }
            }
        },
        "ds_cost": {
            "type": "ds.search",
            "options": {
                "refresh": "60s",
                "refreshType": "delay",
                "query": "| mstats fillnull_value=\"__missing__\" sum(_value) AS total WHERE `agentic_metrics` metric_name=\"agentic.cost.estimated\" BY \"user.email\" \"user.id\" \"service.name\" \"agentic.harness.name\" | eval identity=case('user.email'!=\"__missing__\",'user.email','user.id'!=\"__missing__\",'user.id',true(),null()) | eval svc0='service.name', hn0='agentic.harness.name' | eval hkey=`harness_key(svc0,hn0)` | where \"$selected_user$\"==\"All\" OR identity==\"$selected_user$\" | where \"$selected_service$\"==\"All\" OR hkey==\"$selected_service$\" | stats sum(total) AS total | eval value=case(\"$selected_service$\" IN (\"gemini-cli\",\"codex\"), \"n/a\", isnotnull(total), urldecode(\"%24\").tostring(round(total,2),\"commas\"), true(), null()) | where isnotnull(value) | fields value | appendpipe [| stats count | where count=0 | eval _status=\"Awaiting data\", value=urldecode(\"%24\").\"0\"]",
                "queryParameters": {
                    "earliest": "$tr.earliest$",
                    "latest": "$tr.latest$"
                }
            }
        },
        "ds_loc": {
            "type": "ds.search",
            "options": {
                "refresh": "60s",
                "refreshType": "delay",
                "query": "| mstats fillnull_value=\"__missing__\" sum(_value) AS lines WHERE `agentic_metrics` metric_name=\"agentic.code.lines.changed\" BY \"user.email\" \"user.id\" \"agentic.change.type\" \"service.name\" \"agentic.harness.name\" | eval identity=case('user.email'!=\"__missing__\",'user.email','user.id'!=\"__missing__\",'user.id',true(),null()) | eval svc0='service.name', hn0='agentic.harness.name' | eval hkey=`harness_key(svc0,hn0)` | where \"$selected_user$\"==\"All\" OR identity==\"$selected_user$\" | where \"$selected_service$\"==\"All\" OR hkey==\"$selected_service$\" | stats sum(eval(if('agentic.change.type'==\"added\",lines,0))) AS added sum(eval(if('agentic.change.type'==\"removed\",lines,0))) AS removed | where isnotnull(added) OR isnotnull(removed) | eval value=round((coalesce(added,0)-coalesce(removed,0))/1000,1) | fields value | appendpipe [| stats count | where count=0 | eval _status=\"Awaiting data\", value=0]",
                "queryParameters": {
                    "earliest": "$tr.earliest$",
                    "latest": "$tr.latest$"
                }
            }
        },
        "ds_cache": {
            "type": "ds.search",
            "options": {
                "refresh": "60s",
                "refreshType": "delay",
                "query": "| mstats fillnull_value=\"__missing__\" sum(_value) AS tokens WHERE `agentic_metrics` metric_name=\"agentic.token.usage\" BY \"user.email\" \"user.id\" \"agentic.token.type\" \"agentic.token.relationship\" \"service.name\" \"agentic.harness.name\" | eval identity=case('user.email'!=\"__missing__\",'user.email','user.id'!=\"__missing__\",'user.id',true(),null()) | eval svc0='service.name', hn0='agentic.harness.name' | eval hkey=`harness_key(svc0,hn0)` | where \"$selected_user$\"==\"All\" OR identity==\"$selected_user$\" | where \"$selected_service$\"==\"All\" OR hkey==\"$selected_service$\" | stats sum(eval(if('agentic.token.type'==\"cache_read\" AND 'agentic.token.relationship' IN (\"subset\",\"exclusive\"),tokens,0))) AS cached sum(eval(if(('agentic.token.type'==\"input\" AND 'agentic.token.relationship'==\"total\") OR ('agentic.token.relationship'==\"exclusive\" AND 'agentic.token.type' IN (\"input_uncached\",\"cache_read\",\"cache_creation\")),tokens,0))) AS input_total | where isnotnull(input_total) | eval value=if(input_total>0, round(cached/input_total*100,1), 0) | fields value | appendpipe [| stats count | where count=0 | eval _status=\"Awaiting data\", value=0]",
                "queryParameters": {
                    "earliest": "$tr.earliest$",
                    "latest": "$tr.latest$"
                }
            }
        },
        "ds_leaderboard": {
            "type": "ds.search",
            "options": {
                "refresh": "60s",
                "refreshType": "delay",
                "query": "| mstats fillnull_value=\"__missing__\" sum(_value) AS amount WHERE `agentic_metrics` metric_name IN (\"agentic.token.usage\",\"agentic.cost.estimated\") BY metric_name \"user.email\" \"user.id\" \"agentic.token.type\" \"agentic.token.relationship\" \"service.name\" \"agentic.harness.name\" | eval identity=case('user.email'!=\"__missing__\",'user.email','user.id'!=\"__missing__\",'user.id',true(),null()) | eval svc0='service.name', hn0='agentic.harness.name' | eval hkey=`harness_key(svc0,hn0)` | where \"$selected_user$\"==\"All\" OR identity==\"$selected_user$\" | where \"$selected_service$\"==\"All\" OR hkey==\"$selected_service$\" | stats sum(eval(if(metric_name==\"agentic.token.usage\" AND 'agentic.token.type'==\"cache_read\" AND 'agentic.token.relationship' IN (\"subset\",\"exclusive\"),amount,0))) AS cacheRead sum(eval(if(metric_name==\"agentic.token.usage\" AND (('agentic.token.type'==\"input\" AND 'agentic.token.relationship'==\"total\") OR ('agentic.token.relationship'==\"exclusive\" AND 'agentic.token.type' IN (\"input_uncached\",\"cache_read\",\"cache_creation\"))),amount,0))) AS input_tokens sum(eval(if(metric_name==\"agentic.token.usage\" AND 'agentic.token.relationship' IN (\"total\",\"exclusive\"),amount,0))) AS total_tokens sum(eval(if(metric_name==\"agentic.cost.estimated\",amount,0))) AS cost values(eval(if(metric_name==\"agentic.token.usage\",hkey,null()))) AS svc BY identity | eval User=identity | eval s0=mvindex(svc,0) | eval Service=if(mvcount(svc)>=2, \"Multi\", `harness_label(s0)`) | eval \"Cache %\"=if(input_tokens>0,round(cacheRead/input_tokens*100,1),0) | eval \"Cost ($)\"=if(coalesce(cost,0)>0, round(cost,2), null()) | eval \"Tokens (M)\"=round(total_tokens/1000000,1) | sort - total_tokens | fields User Service \"Tokens (M)\" \"Cost ($)\" \"Cache %\" | appendpipe [| stats count | where count=0 | eval _status=\"Awaiting data\", User=\"\"]",
                "queryParameters": {
                    "earliest": "$tr.earliest$",
                    "latest": "$tr.latest$"
                }
            }
        },
        "ds_timeline": {
            "type": "ds.search",
            "options": {
                "refresh": "60s",
                "refreshType": "delay",
                "query": "| mstats fillnull_value=\"__missing__\" sum(_value) AS tokens WHERE `agentic_metrics` metric_name=\"agentic.token.usage\" span=1h BY \"user.email\" \"user.id\" \"agentic.token.type\" \"agentic.token.relationship\" \"service.name\" \"agentic.harness.name\" | eval identity=case('user.email'!=\"__missing__\",'user.email','user.id'!=\"__missing__\",'user.id',true(),null()) | eval svc0='service.name', hn0='agentic.harness.name' | eval hkey=`harness_key(svc0,hn0)` | where \"$selected_user$\"==\"All\" OR identity==\"$selected_user$\" | where \"$selected_service$\"==\"All\" OR hkey==\"$selected_service$\" | stats sum(eval(if('agentic.token.type'==\"input\" AND 'agentic.token.relationship'==\"total\",tokens,0))) AS input_total sum(eval(if('agentic.token.type'==\"input_uncached\" AND 'agentic.token.relationship'==\"exclusive\",tokens,0))) AS input_uncached sum(eval(if('agentic.token.type'==\"cache_read\" AND 'agentic.token.relationship'==\"subset\",tokens,0))) AS cache_read_subset sum(eval(if('agentic.token.type'==\"cache_read\" AND 'agentic.token.relationship' IN (\"subset\",\"exclusive\"),tokens,0))) AS cache_read sum(eval(if('agentic.token.type'==\"cache_creation\" AND 'agentic.token.relationship'==\"exclusive\",tokens,0))) AS cache_creation sum(eval(if('agentic.token.type'==\"output\" AND 'agentic.token.relationship'==\"total\",tokens,0))) AS output BY _time | eval input=max(input_total+input_uncached-cache_read_subset,0) | fields _time input output cache_read cache_creation | eval hourLabel=strftime(_time,\"%a, %b %d · %H:%M\"), tickLabel=strftime(_time,\"%a %d\") | appendpipe [| stats count | where count=0 | eval _status=\"Awaiting data\"]",
                "queryParameters": {
                    "earliest": "$tr.earliest$",
                    "latest": "$tr.latest$"
                }
            }
        },
        "ds_ratelimit": {
            "type": "ds.search",
            "options": {
                "refresh": "60s",
                "refreshType": "delay",
                "query": "`agentic_data` event.name IN (\"agentic.api_error\",\"gen_ai.client.operation.exception\",\"agentic.api_retries_exhausted\") | eval identity=coalesce('user.email','user.id'), svc0='service.name', hn0='agentic.harness.name' | eval hkey=`harness_key(svc0,hn0)` | where \"$selected_user$\"==\"All\" OR identity==\"$selected_user$\" | where \"$selected_service$\"==\"All\" OR hkey==\"$selected_service$\" | eval is_rl=if(tonumber('http.response.status_code')==429 OR 'error.type'==\"429\" OR match(coalesce('error.type',\"\"), \"(?i)rate.?limit\"),1,0), is_ex=if('event.name'==\"agentic.api_retries_exhausted\",1,0) | where is_rl==1 OR is_ex==1 | eval h=strftime(_time,\"%a %H:00\"), wu=mvindex(split(coalesce(identity,\"unknown\"),\"@\"),0) | stats sum(is_rl) AS c sum(is_ex) AS ex BY h wu | appendpipe [| stats sum(c) AS hc BY h | where hc>0 | sort - hc | head 1 | eval peak_hour=h | fields peak_hour] | appendpipe [| stats sum(c) AS wc BY wu | where wc>0 | sort - wc | head 1 | eval worst_user=wu | fields worst_user] | stats sum(c) AS value sum(ex) AS exhausted values(peak_hour) AS peak_hour values(worst_user) AS worst_user | eval value=coalesce(value,0), foot=\"API retries exhausted: \".coalesce(exhausted,0) | fields value peak_hour worst_user foot | appendpipe [| stats count | where count=0 | eval _status=\"Awaiting data\", value=0]",
                "queryParameters": {
                    "earliest": "$tr.earliest$",
                    "latest": "$tr.latest$"
                }
            }
        },
        "ds_adoption": {
            "type": "ds.search",
            "options": {
                "refresh": "60s",
                "refreshType": "delay",
                "query": "| mstats fillnull_value=\"__missing__\" count(_value) AS points WHERE `agentic_metrics` metric_name=\"agentic.token.usage\" span=1d BY \"user.email\" \"user.id\" \"service.name\" \"agentic.token.relationship\" \"agentic.harness.name\" | eval identity=case('user.email'!=\"__missing__\",'user.email','user.id'!=\"__missing__\",'user.id',true(),null()) | eval svc0='service.name', hn0='agentic.harness.name' | eval hkey=`harness_key(svc0,hn0)` | where 'agentic.token.relationship' IN (\"total\",\"exclusive\") | where \"$selected_service$\"==\"All\" OR hkey==\"$selected_service$\" | where isnotnull(identity) | stats max(_time) AS last_seen BY identity | eventstats max(last_seen) AS latest_day | stats count AS seats count(eval(last_seen==latest_day)) AS value | where seats>0 | eval pct=if(seats>0,round(value/seats*100),0), foot=value.\" of \".seats.\" observed users · \".pct.\"% active on latest day\" | fields value seats pct foot | appendpipe [| stats count | where count=0 | eval _status=\"Awaiting data\", value=0]",
                "queryParameters": {
                    "earliest": "$tr.earliest$",
                    "latest": "$tr.latest$"
                }
            }
        },
        "ds_models": {
            "type": "ds.search",
            "options": {
                "refresh": "60s",
                "refreshType": "delay",
                "query": "| mstats fillnull_value=\"__missing__\" sum(_value) AS tokens WHERE `agentic_metrics` metric_name=\"agentic.token.usage\" BY \"user.email\" \"user.id\" \"gen_ai.request.model\" \"agentic.token.relationship\" \"service.name\" \"agentic.harness.name\" | eval identity=case('user.email'!=\"__missing__\",'user.email','user.id'!=\"__missing__\",'user.id',true(),null()) | eval svc0='service.name', hn0='agentic.harness.name' | eval hkey=`harness_key(svc0,hn0)` | where 'agentic.token.relationship' IN (\"total\",\"exclusive\") | where \"$selected_user$\"==\"All\" OR identity==\"$selected_user$\" | where \"$selected_service$\"==\"All\" OR hkey==\"$selected_service$\" | eval model=if('gen_ai.request.model'==\"__missing__\",\"Unknown\",'gen_ai.request.model') | stats sum(tokens) AS value BY model | sort - value | table model value | appendpipe [| stats count | where count=0 | eval _status=\"Awaiting data\", model=\"\"]",
                "queryParameters": {
                    "earliest": "$tr.earliest$",
                    "latest": "$tr.latest$"
                }
            }
        },
        "ds_heatmap": {
            "type": "ds.search",
            "options": {
                "refresh": "60s",
                "refreshType": "delay",
                "query": "| mstats fillnull_value=\"__missing__\" sum(_value) AS v WHERE `agentic_metrics` metric_name=\"agentic.token.usage\" span=1h BY \"user.email\" \"user.id\" \"agentic.token.relationship\" \"service.name\" \"agentic.harness.name\" | eval identity=case('user.email'!=\"__missing__\",'user.email','user.id'!=\"__missing__\",'user.id',true(),null()) | eval svc0='service.name', hn0='agentic.harness.name' | eval hkey=`harness_key(svc0,hn0)` | where 'agentic.token.relationship' IN (\"total\",\"exclusive\") | where \"$selected_user$\"==\"All\" OR identity==\"$selected_user$\" | where \"$selected_service$\"==\"All\" OR hkey==\"$selected_service$\" | eval daykey=strftime(_time,\"%Y%m%d\"), d=strftime(_time,\"%a %m/%d\"), h=tonumber(strftime(_time,\"%H\")) | stats sum(v) AS v BY daykey d h | sort daykey h | fields d h v | appendpipe [| stats count | where count=0 | eval _status=\"Awaiting data\", d=\"\"]",
                "queryParameters": {
                    "earliest": "$tr.earliest$",
                    "latest": "$tr.latest$"
                }
            }
        },
        "ds_banner": {
            "type": "ds.search",
            "options": {
                "refresh": "60s",
                "refreshType": "delay",
                "query": "| mstats count(_value) AS cnt WHERE `agentic_metrics` metric_name=\"agentic.*\" span=1d | stats sum(cnt) AS cnt | eval lane=\"metrics\" | append [ search `agentic_data` event.name=\"agentic.*\" | head 1 | stats count AS cnt | eval lane=\"events\" ] | append [| makeresults count=2 | streamstats count AS ord0 | eval lane=if(ord0=1,\"metrics\",\"events\"), cnt=0 | fields lane cnt ] | stats sum(cnt) AS cnt BY lane | eventstats max(eval(if(lane==\"metrics\",cnt,0))) AS m_cnt | eval status=case(cnt>0,\"OK\", lane==\"events\" AND m_cnt>0,\"WARN\", true(),\"FAIL\") | eval step=if(lane==\"metrics\",\"No telemetry is reaching the agentic indexes\",\"Metrics flow but no agent events are arriving\") | eval hint=if(lane==\"metrics\",\"Deploy the collector and point your harnesses at it — the Data Health page walks through it\",\"Enable the logs exporter on your harness clients — see Data Health\") | eval ord=if(lane==\"metrics\",1,2) | sort ord | table step status hint",
                "queryParameters": {
                    "earliest": "-24h",
                    "latest": "now"
                }
            }
        },
        "ds_drift": {
            "type": "ds.search",
            "options": {
                "refresh": "60s",
                "refreshType": "delay",
                "query": "| mstats fillnull_value=\"__missing__\" count(_value) AS pts WHERE `agentic_metrics` metric_name IN (\"agentic.token.usage\",\"agentic.code.lines.changed\") BY metric_name \"agentic.token.type\" \"agentic.token.relationship\" \"agentic.change.type\" | stats sum(eval(if(metric_name==\"agentic.token.usage\" AND ('agentic.token.type'==\"__missing__\" OR 'agentic.token.relationship'==\"__missing__\"),pts,0))) AS norel sum(eval(if(metric_name==\"agentic.code.lines.changed\" AND NOT 'agentic.change.type' IN (\"added\",\"removed\"),pts,0))) AS locdrift | appendcols [search `agentic_data` ((event.name=\"agentic.api_request\" AND NOT gen_ai.usage.input_tokens=*) OR (event.name IN (\"agentic.api_request\",\"agentic.api_error\",\"agentic.user_prompt\",\"agentic.tool_result\",\"agentic.tool_execution\",\"agentic.tool_decision\",\"agentic.session_started\",\"agentic.compaction\",\"agentic.subagent_completed\",\"agentic.api_retries_exhausted\",\"agentic.permission_mode_changed\") AND (input_tokens=* OR output_tokens=* OR input_token_count=* OR output_token_count=* OR token_type=* OR cost_usd=* OR cost_usd_micros=* OR duration_ms=* OR model=* OR conversation.id=*)) OR ((event.name=\"*.api_request\" OR event.name=\"*.api_error\" OR event.name=\"*.user_prompt\" OR event.name=\"*.tool_result\" OR event.name=\"*.tool_decision\" OR event.name=\"*.compaction\" OR event.name=\"*.subagent_completed\") AND NOT event.name=\"agentic.*\")) | eval sig=case('event.name'==\"agentic.api_request\" AND isnull('gen_ai.usage.input_tokens'),\"tokenless\", NOT like('event.name',\"agentic.%\"),\"renamed\", true(),\"rawkey\") | stats count(eval(sig==\"tokenless\")) AS tokenless count(eval(sig==\"rawkey\")) AS rawkeys count(eval(sig==\"renamed\")) AS renamed] | appendcols [search `agentic_data` agentic.normalizer.version=* | head 1 | eval nv='agentic.normalizer.version' | fields nv] | eval norel=coalesce(norel,0), locdrift=coalesce(locdrift,0), tokenless=coalesce(tokenless,0), rawkeys=coalesce(rawkeys,0), renamed=coalesce(renamed,0) | eval value=norel+tokenless+rawkeys+renamed+locdrift | eval foot=\"raw keys \".rawkeys.\" · renamed evts \".renamed.\" · loc types \".locdrift.if(isnotnull(nv),\" · norm \".nv,\"\") | fields value norel tokenless foot | appendpipe [| stats count | where count=0 | eval _status=\"Awaiting data\", value=0]",
                "queryParameters": {
                    "earliest": "$tr.earliest$",
                    "latest": "$tr.latest$"
                }
            }
        },
        "ds_harness": {
            "type": "ds.search",
            "options": {
                "refresh": "60s",
                "refreshType": "delay",
                "query": "| mstats fillnull_value=\"__missing__\" sum(_value) AS tokens WHERE `agentic_metrics` metric_name=\"agentic.token.usage\" BY \"user.email\" \"user.id\" \"agentic.token.relationship\" \"service.name\" \"agentic.harness.name\" | eval identity=case('user.email'!=\"__missing__\",'user.email','user.id'!=\"__missing__\",'user.id',true(),null()) | eval svc0='service.name', hn0='agentic.harness.name' | eval hkey=`harness_key(svc0,hn0)` | where 'agentic.token.relationship' IN (\"total\",\"exclusive\") | where \"$selected_user$\"==\"All\" OR identity==\"$selected_user$\" | where \"$selected_service$\"==\"All\" OR hkey==\"$selected_service$\" | stats sum(tokens) AS value BY hkey | eval harness=`harness_label(hkey)` | sort - value | table harness value | appendpipe [| stats count | where count=0 | eval _status=\"Awaiting data\", harness=\"\"]",
                "queryParameters": {
                    "earliest": "$tr.earliest$",
                    "latest": "$tr.latest$"
                }
            }
        }
    },
